import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { Button } from "@/shadcn/components/ui/button";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { PERMISSIONS } from "@/constants/permissions";
import HarmonyForm from "@/components/forms/HarmonyForm";
import { Loader2, AlertCircle } from "lucide-react";

interface UserFormDialogProps {
  open: boolean;
  onClose: () => void;
  editingId: string | null;
  activeTab: string;
  userType: string;
  onUserTypeChange: (type: string) => void;
  isFetchingEdit: boolean;
  selectedUserData: any;
  error: string | null;
  isSubmitting: boolean;
  onSubmit: (data: any) => void;
}

export function UserFormDialog({
  open,
  onClose,
  editingId,
  activeTab,
  userType,
  onUserTypeChange,
  isFetchingEdit,
  selectedUserData,
  error,
  isSubmitting,
  onSubmit,
}: UserFormDialogProps) {
  return (
    <HarmonyDialog
      open={open}
      onOpenChange={(isOpen) => { if (!isOpen) onClose(); }}
      title={editingId ? "Edit User" : "Add New User"}
      description={editingId ? "Modify existing record" : `Register new ${userType}`}
      size="2xl"
      footerChildren={
        <div className="flex justify-end gap-3 w-full">
          <Button variant="secondary" onClick={onClose} disabled={isSubmitting}>
            Cancel
          </Button>
          <PermissionGate
            permission={
              editingId
                ? activeTab === "employee"
                  ? PERMISSIONS.Employee.Update
                  : PERMISSIONS.Intern.Update
                : userType === "employee"
                ? PERMISSIONS.Employee.Create
                : PERMISSIONS.Intern.Create
            }
            mode="disable"
          >
            <Button
              disabled={isSubmitting}
              onClick={() => document.querySelector("form")?.requestSubmit?.()}
            >
              {isSubmitting && <Loader2 className="w-4 h-4 animate-spin" />}
              {editingId ? "Update Record" : "Create User"}
            </Button>
          </PermissionGate>
        </div>
      }
    >
      <div className="space-y-4">
        {!editingId && (
          <div className="flex gap-3 pb-2 border-b border-border">
            {["employee", "intern"].map((type) => (
              <button
                key={type}
                onClick={() => onUserTypeChange(type)}
                className={`px-4 py-2.5 rounded-lg text-sm font-semibold transition ${
                  userType === type
                    ? "bg-primary text-primary-foreground shadow-md shadow-primary/20"
                    : "bg-muted border border-border text-foreground hover:bg-muted/80"
                }`}
              >
                {type === "employee" ? "Employee" : "Intern"}
              </button>
            ))}
          </div>
        )}

        {error && (
          <div
            className="p-4 bg-destructive/10 border border-destructive/20 text-destructive rounded-lg flex gap-3 text-sm"
            role="alert"
          >
            <AlertCircle size={18} className="flex-shrink-0 mt-0.5" />
            <span className="font-medium">{error}</span>
          </div>
        )}

        {isFetchingEdit ? (
          <div className="flex justify-center items-center gap-2 py-12 text-muted-foreground">
            <Loader2 size={20} />
            <span className="font-medium">Loading user data...</span>
          </div>
        ) : (
          <HarmonyForm
            key={editingId || userType}
            dtoName={
              editingId
                ? activeTab === "employee"
                  ? "EmployeeRegisterDTO"
                  : "InternRegisterDTO"
                : userType === "employee"
                ? "EmployeeRegisterDTO"
                : "InternRegisterDTO"
            }
            onSubmit={onSubmit}
            defaultValues={editingId ? selectedUserData : undefined}
            hideSubmitButton={true}
          />
        )}
      </div>
    </HarmonyDialog>
  );
}
