import { useState, useEffect } from 'react';

import { Plus, Loader2, AlertCircle, Trash2, Edit2, Search, UserX, UserCheck } from 'lucide-react';
import { Button } from '@/shadcn/components/ui/button';
import { userService as accountService } from '@/api/auth/userService';
import { adminService } from '@/api/auth/adminService';
import { getApiErrorMessage } from '@/api/app/apiError';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';

import { PermissionGate } from '@/components/shared/PermissionGate';
import { PERMISSIONS } from '@/constants/permissions';
import { HarmonyAlertDialog } from '@/components/ui/harmony-alert-dialog';
import { UserFormDialog } from '@/features/users/components/UserFormDialog';
import { Tabs, TabsList, TabsTrigger } from '@/shadcn/components/ui/tabs';

import type { User } from '@/types/user';

const ManageUsers = () => {
  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
  const [userType, setUserType] = useState<string>("employee");
  const [activeTab, setActiveTab] = useState<string>("employee");
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [refreshKey, setRefreshKey] = useState<number>(0);
  const [deleteError, setDeleteError] = useState<string | null>(null);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [otpUpdatingId, setOtpUpdatingId] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [isFetchingEdit, setIsFetchingEdit] = useState<boolean>(false);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [selectedUserData, setSelectedUserData] = useState<any>(null);
  const [userToDelete, setUserToDelete] = useState<User | null>(null);
  const [activeUpdatingId, setActiveUpdatingId] = useState<string | null>(null);
  const [userToToggle, setUserToToggle] = useState<User | null>(null);


  const queryClient = useQueryClient();
  const [searchId, setSearchId] = useState<string>('');

  // ── MUTATIONS ──────────────────────────────────────────────────────────

  const deleteMutation = useMutation({
    mutationFn: (id: string) => {
      if (activeTab === 'employee') return accountService.deleteEmployee(id);
      return accountService.deleteIntern(id);
    },
    onMutate: async (id) => {
      await queryClient.cancelQueries({ queryKey: ['users', activeTab, refreshKey] });
      const previousUsers = queryClient.getQueryData<User[]>(['users', activeTab, refreshKey]);
      queryClient.setQueryData<User[]>(['users', activeTab, refreshKey], (old) =>
        old?.filter(u => u.id !== id)
      );
      return { previousUsers };
    },
    onError: (err, _id, context) => {
      queryClient.setQueryData(['users', activeTab, refreshKey], context?.previousUsers);
      setDeleteError(getApiErrorMessage(err, 'Failed to delete user. Rolling back...'));
    },
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: ['users', activeTab, refreshKey] });
      setDeletingId(null);
    },
    onSuccess: () => {
      setSuccessMessage('User deleted successfully.');
    }
  });

  const otpMutation = useMutation({
    mutationFn: ({ id, enabled }: { id: string, enabled: boolean }) =>
      accountService.setUserOtpEnabled(id, enabled),
    onMutate: async ({ id, enabled }) => {
      await queryClient.cancelQueries({ queryKey: ['users', activeTab, refreshKey] });
      const previousUsers = queryClient.getQueryData<User[]>(['users', activeTab, refreshKey]);
      queryClient.setQueryData<User[]>(['users', activeTab, refreshKey], (old) =>
        old?.map(u => u.id === id ? { ...u, otpEnabled: enabled } : u)
      );
      return { previousUsers };
    },
    onError: (err, _variables, context) => {
      queryClient.setQueryData(['users', activeTab, refreshKey], context?.previousUsers);
      setError(getApiErrorMessage(err, 'Failed to update OTP. Rolling back...'));
    },
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: ['users', activeTab, refreshKey] });
      setOtpUpdatingId(null);
    },
    onSuccess: (_, variables) => {
      setSuccessMessage(`OTP ${variables.enabled ? 'enabled' : 'disabled'} successfully.`);
    }
  });

  const { data: employeesData = [], isLoading: isLoadingEmployees, isError: isErrorEmp, error: queryErrorEmp } = useQuery<User[]>({
    queryKey: ['users', 'employee', refreshKey],
    queryFn: () => accountService.getEmployees({ includeInactive: true }),
  });

  const { data: internsData = [], isLoading: isLoadingInterns, isError: isErrorIntern, error: queryErrorIntern } = useQuery<User[]>({
    queryKey: ['users', 'intern', refreshKey],
    queryFn: () => accountService.getInterns({ includeInactive: true }),
  });

  const isLoading = isLoadingEmployees || isLoadingInterns;
  const isError = isErrorEmp || isErrorIntern;
  const queryError = queryErrorEmp || queryErrorIntern;

  const usersData: User[] = activeTab === 'employee'
    ? employeesData.filter(u => u.isActive !== false)
    : activeTab === 'intern'
    ? internsData.filter(u => u.isActive !== false)
    : [...employeesData, ...internsData].filter(u => u.isActive === false);




  const activeMutation = useMutation({
    mutationFn: ({ userId, active }: { userId: string, active: boolean }) =>
      adminService.setUserActive(userId, active),
    onMutate: async ({ userId, active }) => {
      setActiveUpdatingId(userId);
      for (const tab of ['employee', 'intern']) {
        await queryClient.cancelQueries({ queryKey: ['users', tab, refreshKey] });
        queryClient.setQueryData<User[]>(['users', tab, refreshKey], (old) =>
          old?.map(u => u.id === userId ? { ...u, isActive: active } : u)
        );
      }
      return {};
    },
    onSuccess: (_data, variables) => {
      setSuccessMessage(`User ${variables.active ? 'enabled' : 'disabled'} successfully.`);
    },
    onError: (err) => {
      setError(getApiErrorMessage(err, 'Failed to update user status.'));
    },
    onSettled: () => {
      setActiveUpdatingId(null);
      queryClient.invalidateQueries({ queryKey: ['users', 'employee', refreshKey] });
      queryClient.invalidateQueries({ queryKey: ['users', 'intern', refreshKey] });
    }
  });

  useEffect(() => {
    setSearchId('');
  }, [activeTab]);

  useEffect(() => {
    if (successMessage) {
      const timer = setTimeout(() => {
        setSuccessMessage(null);
      }, 3000);
      return () => clearTimeout(timer);
    }
  }, [successMessage]);

  const handleOpenModal = () => {
    setError(null);
    setEditingId(null);
    setSelectedUserData(null);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setError(null);
    setEditingId(null);
    setSelectedUserData(null);
  };

  const handleEdit = async (user: User) => {
    try {
      setIsFetchingEdit(true);
      setError(null);
      setUserType(activeTab);
      setSuccessMessage(null);

      let data;
      if (activeTab === 'employee') {
        data = await accountService.getEmployeeById(user.id);
      } else {
        data = await accountService.getInternById(user.id);
      }

      setEditingId(user.id);
      setSelectedUserData(data);
      setIsModalOpen(true);
    } catch (err) {
      setError('Failed to load user details. Please try again.');
      console.error('Edit error:', err);
    } finally {
      setIsFetchingEdit(false);
    }
  };

  const handleSubmit = async (data: any) => {
    try {
      setIsSubmitting(true);
      setError(null);
      setSuccessMessage(null);

      if (editingId) {
        if (activeTab === "employee") {
          await accountService.updateEmployee(editingId, data);
        } else {
          await accountService.updateIntern(editingId, data);
        }
        setSuccessMessage('User updated successfully.');
      } else {
        if (userType === "employee") {
          await accountService.registerEmployee(data);
        } else {
          await accountService.registerIntern(data);
        }
        setSuccessMessage('User created successfully.');
      }

      setTimeout(() => {
        handleCloseModal();
        setRefreshKey(prev => prev + 1);
      }, 400);
    } catch (err) {
      setError(getApiErrorMessage(err));
      console.error('Submit error:', err);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = (user: User) => {
    setUserToDelete(user);
  };

  const confirmDelete = () => {
    if (!userToDelete) return;
    setDeletingId(userToDelete.id);
    deleteMutation.mutate(userToDelete.id, {
        onSuccess: () => {
            setUserToDelete(null);
        }
    });
  };

  const handleToggleOtp = (user: User) => {
    setOtpUpdatingId(user.id);
    setError(null);
    const nextEnabled = !(user.otpEnabled ?? true);
    otpMutation.mutate({ id: user.id, enabled: nextEnabled });
  };

  const displayUsers: User[] = searchId.trim()
    ? usersData.filter(u =>
        u.email?.toLowerCase().includes(searchId.toLowerCase().trim()) ||
        u.employeeID?.toLowerCase().includes(searchId.toLowerCase().trim()) ||
        u.enrollmentId?.toLowerCase().includes(searchId.toLowerCase().trim()) ||
        `${u.firstName || ''} ${u.lastName || ''}`.toLowerCase().includes(searchId.toLowerCase().trim())
      )
    : usersData;

  return (
    <div className="page-wrapper">
      <div className="max-w-6xl mx-auto">
        {/* Success Message */}
        {successMessage && (
          <div className="mb-6 p-4 bg-emerald-50 border border-emerald-200 text-emerald-700 rounded-lg flex items-start gap-3 text-sm shadow-sm" role="alert">
            <AlertCircle size={18} className="flex-shrink-0 mt-0.5" />
            <span className="font-medium">{successMessage}</span>
          </div>
        )}

        {/* Error Messages */}
        {deleteError && (
          <div className="mb-6 p-4 bg-destructive/10 border border-destructive/20 text-destructive rounded-lg flex items-start gap-3 text-sm shadow-sm" role="alert">
            <AlertCircle size={18} className="flex-shrink-0 mt-0.5" />
            <span className="font-medium">{deleteError}</span>
          </div>
        )}

        {isError && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 text-red-700 rounded-lg flex items-start justify-between gap-3 text-sm shadow-sm" role="alert">
            <div className="flex items-start gap-3">
              <AlertCircle size={18} className="flex-shrink-0 mt-0.5" />
              <div>
                <p className="font-bold">Failed to load users</p>
                <p className="font-medium mt-0.5">{getApiErrorMessage(queryError)}</p>
              </div>
            </div>
            <button
              onClick={() => setRefreshKey(prev => prev + 1)}
              className="px-3 py-1 bg-destructive/20 hover:bg-destructive/30 text-destructive rounded-md text-xs font-bold transition-colors"
            >
              Retry
            </button>
          </div>
        )}

        {/* Header Section */}
        <div className="page-header">
          <div>
            <h1 className="page-title">Manage Users</h1>
            <p className="page-subtitle">View, edit, and manage employees and interns</p>
          </div>
          <PermissionGate permission={activeTab === 'employee' ? PERMISSIONS.Employee.Create : PERMISSIONS.Intern.Create} mode="disable">
            <Button onClick={handleOpenModal} aria-label="Add new user">
              <Plus size={16} /> Add User
            </Button>
          </PermissionGate>
        </div>

        {/* Tabs and Search Section */}
        <div className="section-card p-5 mb-6">
          {/* Tabs */}
          <Tabs value={activeTab} onValueChange={setActiveTab} className="mb-5">
            <TabsList variant="line">
              <TabsTrigger value="employee">Employees</TabsTrigger>
              <TabsTrigger value="intern">Interns</TabsTrigger>
              <TabsTrigger value="disabled" className="text-rose-400 data-[state=active]:text-rose-600 data-[state=active]:border-rose-500">
                <span className="flex items-center gap-1.5">
                  <UserX size={13} />
                  Disabled Users
                  {[...employeesData, ...internsData].filter(u => u.isActive === false).length > 0 && (
                    <span className="ml-1 px-1.5 py-0.5 bg-rose-100 text-rose-600 rounded-full text-[10px] font-black">
                      {[...employeesData, ...internsData].filter(u => u.isActive === false).length}
                    </span>
                  )}
                </span>
              </TabsTrigger>
            </TabsList>
          </Tabs>

          {/* Search Bar */}
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="flex-1 relative">
              <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
              <input
                type="text"
                value={searchId}
                onChange={(e) => setSearchId(e.target.value)}
                placeholder={`Search by Name, Email, or ${activeTab === "employee" ? "Employee ID" : "Enrollment ID"}...`}
                aria-label="Search users"
                className="form-input pl-9"
              />
            </div>
            {searchId && (
              <Button variant="outline" onClick={() => setSearchId('')} aria-label="Clear search">
                Clear
              </Button>
            )}
          </div>
        </div>

        {/* Users List */}
        <div role="region" aria-label="Users list" className="section-card overflow-hidden">
          {isLoading ? (
            <div className="py-12 text-center text-muted-foreground text-sm">Loading Data...</div>
          ) : displayUsers.length > 0 ? (
            displayUsers.map((user: User) => (
              <div
                key={user.id}
                className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 px-6 py-4 border-b border-border/30 last:border-0 hover:bg-muted/20 transition-colors"
              >
                <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 w-full">
                  {/* User Info */}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-start gap-3">
                      <div className="flex-1">
                        <h3 className="text-sm font-bold text-foreground">
                          {user.fullName || user.firstName ? `${user.firstName || ''} ${user.lastName || ''}`.trim() : 'N/A'}
                        </h3>
                        <div className="mt-2 grid grid-cols-1 sm:grid-cols-2 gap-2">
                          <div className="text-xs">
                            <span className="text-muted-foreground font-medium">{activeTab === "employee" ? "Employee ID:" : "Enrollment ID:"}</span>
                            <p className="text-foreground font-semibold mt-0.5">{activeTab === "employee" ? user.employeeID : user.enrollmentId || 'N/A'}</p>
                          </div>
                          <div className="text-xs">
                            <span className="text-muted-foreground font-medium">Email:</span>
                            <p className="text-foreground font-semibold mt-0.5 truncate">{user.email || 'N/A'}</p>
                          </div>

                          <div className="text-xs">
                            <span className="text-slate-500 font-medium">Role:</span>
                            <p className="text-slate-800 font-semibold mt-0.5 capitalize">{user.role || (user.employeeID ? 'Employee' : user.enrollmentId ? 'Intern' : 'User')}</p>
                          </div>

                          <div className="text-xs">
                            <span className="text-muted-foreground font-medium">Account Status:</span>
                            <div className="mt-1">
                              <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest border ${
                                (user.isActive !== false)
                                  ? 'bg-emerald-50 text-emerald-700 border-emerald-200'
                                  : 'bg-rose-50 text-rose-600 border-rose-200'
                              }`}>
                                {(user.isActive !== false) ? 'Active' : 'Disabled'}
                              </span>
                            </div>
                          </div>

                          <div className="text-xs">
                            <span className="text-muted-foreground font-medium">User OTP:</span>
                            <p className={`font-semibold mt-0.5 ${(user.otpEnabled ?? true) ? 'text-emerald-700 dark:text-emerald-400' : 'text-amber-700 dark:text-amber-400'}`}>
                              {(user.otpEnabled ?? true) ? 'Enabled' : 'Disabled'}
                            </p>
                          </div>
                          {user.phoneNumber && (
                            <div className="text-xs">
                              <span className="text-muted-foreground font-medium">Phone:</span>
                              <p className="text-foreground font-semibold mt-0.5">{user.phoneNumber}</p>
                            </div>
                          )}
                          {activeTab === "intern" && user.collegeName && (
                            <div className="text-xs">
                              <span className="text-muted-foreground font-medium">College:</span>
                              <p className="text-foreground font-semibold mt-0.5 truncate">{user.collegeName}</p>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* Actions */}
                  <div className="flex gap-2 flex-shrink-0 sm:ml-4 flex-wrap justify-end">

                    {/* Disable / Enable toggle — always visible */}
                    <PermissionGate permission={PERMISSIONS.User.Update} mode="disable">
                      <button
                        onClick={() => setUserToToggle(user)}
                        aria-label={`${user.isActive === false ? 'Enable' : 'Disable'} ${user.firstName || 'user'}`}
                        disabled={activeUpdatingId === user.id}
                        aria-busy={activeUpdatingId === user.id}
                        className={`inline-flex items-center gap-2 px-4 py-2 rounded-lg transition text-sm font-semibold border ${
                          activeUpdatingId === user.id
                            ? 'bg-muted text-muted-foreground border-border cursor-not-allowed'
                            : user.isActive === false
                              ? 'bg-emerald-50 dark:bg-emerald-950/40 hover:bg-emerald-100 dark:hover:bg-emerald-950/60 text-emerald-700 dark:text-emerald-400 border-emerald-200 dark:border-emerald-800 hover:border-emerald-300'
                              : 'bg-rose-50 dark:bg-rose-950/40 hover:bg-rose-100 dark:hover:bg-rose-950/60 text-rose-600 dark:text-rose-400 border-rose-200 dark:border-rose-800 hover:border-rose-300'
                        }`}
                      >
                        {activeUpdatingId === user.id ? (
                          <Loader2 size={14} className="animate-spin" />
                        ) : user.isActive === false ? (
                          <><UserCheck size={14} /> Enable</>
                        ) : (
                          <><UserX size={14} /> Disable</>
                        )}
                      </button>
                    </PermissionGate>

                    {/* OTP toggle — only for active users */}
                    {user.isActive !== false && (
                      <PermissionGate permission={PERMISSIONS.User.Update} mode="disable">
                        <button
                          onClick={() => handleToggleOtp(user)}
                          aria-label={`Toggle OTP for ${user.firstName || 'user'}`}
                          disabled={otpUpdatingId === user.id}
                          aria-busy={otpUpdatingId === user.id}
                          className={`inline-flex items-center gap-2 px-4 py-2 rounded-lg transition text-sm font-semibold border ${otpUpdatingId === user.id
                            ? 'bg-muted text-muted-foreground border-border cursor-not-allowed'
                            : (user.otpEnabled ?? true)
                              ? 'bg-amber-50 dark:bg-amber-950/40 hover:bg-amber-100 dark:hover:bg-amber-950/60 text-amber-700 dark:text-amber-400 border-amber-200 dark:border-amber-800 hover:border-amber-300'
                              : 'bg-emerald-50 dark:bg-emerald-950/40 hover:bg-emerald-100 dark:hover:bg-emerald-950/60 text-emerald-700 dark:text-emerald-400 border-emerald-200 dark:border-emerald-800 hover:border-emerald-300'
                            }`}
                        >
                          {otpUpdatingId === user.id
                            ? <Loader2 size={14} className="animate-spin" />
                            : <>{(user.otpEnabled ?? true) ? 'Disable OTP' : 'Enable OTP'}</>
                          }
                        </button>
                      </PermissionGate>
                    )}

                    {/* Edit — only for active users */}
                    {user.isActive !== false && (
                      <PermissionGate permission={activeTab === 'employee' ? PERMISSIONS.Employee.Update : PERMISSIONS.Intern.Update} mode="disable">
                        <button
                          onClick={() => handleEdit(user)}
                          aria-label={`Edit ${user.firstName || 'user'}`}
                          disabled={isFetchingEdit}
                          className="inline-flex items-center gap-2 px-4 py-2 bg-muted hover:bg-card text-foreground rounded-lg transition disabled:opacity-50 disabled:cursor-not-allowed text-sm font-semibold border border-border hover:border-primary hover:text-primary shadow-sm active:scale-95"
                        >
                          <Edit2 size={14} /> Edit
                        </button>
                      </PermissionGate>
                    )}

                    {/* Delete — always available */}
                    <PermissionGate
                      permission={
                        (activeTab === 'employee' || (activeTab === 'disabled' && (user as any)._type !== 'intern'))
                          ? PERMISSIONS.Employee.Delete
                          : PERMISSIONS.Intern.Delete
                      }
                      mode="disable"
                    >
                      <button
                        onClick={() => handleDelete(user)}
                        aria-label={`Delete ${user.firstName || 'user'}`}
                        disabled={deletingId === user.id}
                        aria-busy={deletingId === user.id}
                        className={`inline-flex items-center gap-2 px-4 py-2 rounded-lg transition text-sm font-semibold border ${deletingId === user.id
                          ? 'bg-muted text-muted-foreground border-border cursor-not-allowed'
                          : 'bg-red-50 dark:bg-red-950/40 hover:bg-red-100 dark:hover:bg-red-950/60 text-red-600 dark:text-red-400 border-red-200 dark:border-red-800 hover:border-red-300'
                          }`}
                      >
                        {deletingId === user.id
                          ? <Loader2 size={14} className="animate-spin" />
                          : <><Trash2 size={14} /> Delete</>
                        }
                      </button>
                    </PermissionGate>
                  </div>
                </div>
              </div>
            ))
          ) : (
            <div className="bg-card rounded-lg border border-border p-12 flex flex-col items-center justify-center">
              <div className="text-center">
                <AlertCircle size={48} className="text-muted-foreground/30 mx-auto mb-4" />
                <p className="text-foreground font-semibold">
                  {searchId ? `No user found with ID "${searchId}"` : `No users found`}
                </p>
                <p className="text-muted-foreground text-sm mt-1">
                  {!searchId ? `Start by adding a new ${activeTab}` : 'Try a different search'}
                </p>
              </div>
            </div>
          )}
        </div>

        <UserFormDialog
          open={isModalOpen}
          onClose={handleCloseModal}
          editingId={editingId}
          activeTab={activeTab}
          userType={userType}
          onUserTypeChange={setUserType}
          isFetchingEdit={isFetchingEdit}
          selectedUserData={selectedUserData}
          error={error}
          isSubmitting={isSubmitting}
          onSubmit={handleSubmit}
        />

        {userToDelete && (
          <HarmonyAlertDialog
            open={!!userToDelete}
            onOpenChange={(open) => { if (!open) setUserToDelete(null); }}
            variant="danger"
            title={`Delete ${activeTab === 'employee' ? 'Employee' : 'Intern'}`}
            description={`This will permanently remove ${userToDelete.fullName || userToDelete.firstName || 'this user'} from the system. This action cannot be undone.`}
            actionLabel="Permanently Delete"
            onAction={confirmDelete}
            isActioning={deleteMutation.isPending}
          />
        )}

        {/* Disable / Enable Confirmation Modal */}
        {userToToggle && (
          <HarmonyAlertDialog
            open={!!userToToggle}
            onOpenChange={(open) => { if (!open) setUserToToggle(null); }}
            variant={userToToggle.isActive === false ? "default" : "warning"}
            title={userToToggle.isActive === false ? "Enable User Account" : "Disable User Account"}
            description={
              userToToggle.isActive === false
                ? `This will re-enable ${userToToggle.fullName || userToToggle.firstName || "this user"}'s account. They will be able to log in and access the system again.`
                : `This will disable ${userToToggle.fullName || userToToggle.firstName || "this user"}'s account. They will no longer be able to log in or access the system. You can re-enable them from the Disabled Users tab.`
            }
            actionLabel={userToToggle.isActive === false ? "Enable Account" : "Disable Account"}
            onAction={() => {
              const willEnable = userToToggle.isActive === false;
              activeMutation.mutate(
                { userId: userToToggle.id, active: willEnable },
                { onSuccess: () => setUserToToggle(null) }
              );
            }}
            isActioning={activeMutation.isPending}
          />
        )}
      </div>
    </div>
  );
};

export default ManageUsers;
