import api from '../app/client';

export const adminService = {
  setUserRole: (userId: string, role: string) =>
    api.patch(`/admin/users/${userId}/role`, { role }).then(r => r.data),

  setUserActive: (userId: string, active: boolean) =>
    api.patch(`/admin/users/${userId}/active`, { active }).then(r => r.data),

  hardDelete: (entityType: string, id: string) =>
    api.delete(`/admin/hard-delete/${entityType}/${id}`).then(r => r.data),

  getLogLevel: () =>
    api.get('/admin/log-level').then(r => r.data),

  setLogLevel: (level: string) =>
    api.patch('/admin/log-level', { level }).then(r => r.data),
};
